mapper.select:
select i.business_type, i.business_key, i.form_data as form_data_str, i.flow_id, f.flow_name, i.status, f.ent_code, e.ent_name, i.current_node_id, n.node_name as current_node_name, i.current_assignee, u1.user_name as current_assignee_name, i.initiator, u2.user_name as initiator_name, i.create_time, i.update_time from t_bas_approval_instance i left join t_bas_approval_flow f on f.flow_id = i.flow_id left join t_bas_enterprise e on e.ent_code = f.ent_code left join t_bas_approval_node n on n.node_id = i.current_node_id left join sys_user u1 on u1.user_id = i.current_assignee left join sys_user u2 on u2.user_id = i.initiator
and i.business_type = #{businessType}
and i.status = #{status}
and f.ent_code = #{entCode}
and f.ent_code in
#{entCode}
order by i.update_time desc, i.create_time desc

select h.id, h.action_type, h.action_user, u.user_name as action_user_name, h.action_time, h.comment, h.node_id, n.node_name, h.ip_address, h.action_location, h.browser, h.os from t_bas_approval_history h left join t_bas_approval_node n on n.node_id = h.node_id left join sys_user u on u.user_id = h.action_user
and h.business_type = #{businessType}
and h.business_key = #{businessKey}
order by h.action_time asc

select count(1)
from t_bas_approval_instance
where business_type = #{businessType} and business_key = #{businessKey}

mapper.update:
update t_bas_approval_instance
set status = #{status}, current_node_id = #{currentNodeId}, current_assignee = #{currentAssignee}
where business_type = #{businessType} and business_key = #{businessKey}

mapper.select:
select m.id, m.history_id, m.push_user, u.user_name as push_user_name, m.message_content, m.push_status, m.push_time, m.read_time, m.max_retries, m.retry_interval, m.create_time, m.update_time from t_bas_approval_message m left join sys_user u on u.user_id = m.push_user
and m.push_user = #{userId}
and m.push_status = #{pushStatus}
order by m.push_time desc

mapper.update:
update t_bas_approval_message
set push_status = 1, read_time = #{readTime}
where id = #{messageId}
